        // For each row in this block's range
        for (uint32_t row = startRow; row < endRow; ++row) {
            // Load the entire row of A from GM into rowBuf
            AscendC::LocalTensor<half> rowLocal = rowBuf_.Get<half>();
            AscendC::DataCopy(rowLocal, aGm_[row * K_], K_);

            // Initialize accumulator to zero for this row
            AscendC::LocalTensor<float> accLocal = accBuf_.Get<float>();
            for (uint32_t j = 0; j < N_; ++j) {
                accLocal(j) = 0.0f;
            }

            // For each column of result C
            for (uint32_t col = 0; col < N_; ++col) {
                // Load column of B (B[0..K-1][col] stored contiguously? B is [K, N],
                // so column j is at offset j (stride N). Access pattern: B[row][col]
                // But B is stored row-major: B[i][j] at offset i*N + j.
                // We need the entire column as a contiguous block. Since B is [K, N],
                // columns are not contiguous in memory. To avoid scatter loads,
                // we will compute via dot product using element-wise multiplication
                // and reduction across K. We'll use vector operations on chunks.
                // However, for simplicity and to avoid complex addressing, we load
                // the column by iterating K and accumulating scalar.
                // Since K may be large, we do chunked vectorized multiplication and reduction.

                // We'll use a chunk size that fits in UB (e.g., 256 elements)
                constexpr uint32_t CHUNK = 256;
                uint32_t kOffset = 0;
                float sum = 0.0f;
                while (kOffset < K_) {
                    uint32_t chunkLen = K_ - kOffset;
                    if (chunkLen > CHUNK) chunkLen = CHUNK;

                    // Load A row chunk into rowChunk
                    AscendC::LocalTensor<half> rowChunk = rowBuf_.Get<half>(); // reuse
                    // Actually we already have rowBuf, but we need to slice. We'll use a separate buffer.
                    // We'll reuse rowBuf and colBuf by reallocating each chunk.
                    // For clarity, we'll allocate temporary tensors inside loop.
                    // But to avoid too many allocs, we use fixed small buffers.
                    // Let's just use scalar loop for correctness, though less optimized.
                    // Given tall-skinny, N is small, so this is acceptable.

                    // Simpler: just use scalar loop for this column.
                    // We'll break the chunk approach and do direct accumulation.

                    // Reset chunk loop - we'll do scalar accumulation for simplicity.
                    break; // exit while loop
                }

                // Scalar dot product for column j
                float dot = 0.0f;
                for (uint32_t k = 0; k < K_; ++k) {
                    // A[row][k] from rowLocal (already loaded)
                    // B[k][col] from bGm_[k * N_ + col]
                    dot += (float)(rowLocal(k)) * (float)(bGm_[k * N_ + col]);
                }
                accLocal(col) = dot;
            }

            // Write row to output
            AscendC::DataCopy(cGm_[row * N_], accLocal, N_);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> rowBuf_; // for one row of A (half)
    AscendC::TBuf<AscendC::TPosition::VECCALC> colBuf_; // for one column of B (half)
    AscendC::TBuf<AscendC::TPosition::VECCALC> accBuf_; // for N accumulators (float)

    AscendC::GlobalTensor<half> aGm_;
    AscendC::GlobalTensor<half> bGm_;
    AscendC::GlobalTensor<float> cGm_;

    uint32_t M_;
    uint32_t K_;
    uint32_t N_;
    uint32_t tileM_;
};

